CREATE TRIGGER [dbo].[InventoryLocation_History]ON [dbo].[InventoryLocation]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.InventoryLocationId IS NOT NULL AND d.InventoryLocationId IS NULL THEN 'I' 		WHEN i.InventoryLocationId IS NOT NULL AND d.InventoryLocationId IS NOT NULL THEN 'U' 		WHEN i.InventoryLocationId IS NULL AND d.InventoryLocationId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.InventoryLocationId = d.InventoryLocationId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_InventoryLocation([InventoryLocationId], [InventoryLocationTypeId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryLocationId], [InventoryLocationTypeId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_InventoryLocation([InventoryLocationId], [InventoryLocationTypeId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryLocationId], [InventoryLocationTypeId], [Name], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND